package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithHeaderCommentsNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withHeaderComments((Object[]) null);
        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertNull(newFormat.getHeaderComments());
    }

    @Test
    void testWithHeaderCommentsEmpty() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withHeaderComments(new Object[0]);
        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertNotNull(newFormat.getHeaderComments());
        assertEquals(0, newFormat.getHeaderComments().length);
    }

    @Test
    void testWithHeaderCommentsSingle() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withHeaderComments("comment1");
        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertArrayEquals(new String[] {"comment1"}, newFormat.getHeaderComments());
    }

    @Test
    void testWithHeaderCommentsMultiple() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withHeaderComments("comment1", "comment2", "comment3");
        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertArrayEquals(new String[] {"comment1", "comment2", "comment3"}, newFormat.getHeaderComments());
    }

    @Test
    void testWithHeaderCommentsWithNullElement() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = format.withHeaderComments("comment1", null, "comment3");
        assertNotNull(newFormat);
        assertNotSame(format, newFormat);
        assertArrayEquals(new String[] {"comment1", null, "comment3"}, newFormat.getHeaderComments());
    }
}
